-- Locations V1 — preparatory schema for marina import (ships BEFORE the marina import migration)
--
-- Adds country_code to regions and geocoordinate/OSM provenance columns to ports.
-- The 00102_marinas_v1_expansion.sql migration (generated by the Python pipeline)
-- depends on these columns existing at apply time.

alter table public.regions
  add column if not exists country_code char(2) null;

alter table public.ports
  add column if not exists latitude numeric(9, 6) null,
  add column if not exists longitude numeric(9, 6) null,
  add column if not exists osm_type text null check (osm_type in ('node','way','relation')),
  add column if not exists osm_id bigint null,
  add column if not exists website text null,
  add column if not exists phone text null,
  add column if not exists capacity text null,
  add column if not exists vhf text null;

create index if not exists idx_ports_lat_lon
  on public.ports (latitude, longitude)
  where latitude is not null;

create unique index if not exists idx_ports_osm
  on public.ports (osm_type, osm_id)
  where osm_id is not null;
